-- Program: Pilates & Stretch Fusion
-- Category: Pilates -> pilates
-- Priority: Low
-- Durations: [2, 4, 8], Sessions: [3, 4]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Pilates & Stretch Fusion',
    'Fusion of Pilates core work with deep stretching for flexibility, combining strength and suppleness',
    'pilates',
    'all_levels',
    8,
    4,
    'push_pull_legs',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Improve flexibility', 'Enhance body awareness']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Pilates & Stretch Fusion - 2w 3x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Pilates & Stretch Fusion - 2w 3x/wk',
    'pilates',
    3,
    60,
